import React, { useState } from 'react';
interface BaseComponentProps {
  className?: string;
  style?: React.CSSProperties;
  children?: React.ReactNode;
}
const ProjectCard = ({
  title,
  image,
  icon
}: {
  title: string;
  image: string;
  icon: string;
}) => {
  const [isHovered, setIsHovered] = useState(false);
  return <article className="ca-interactive-card" onMouseEnter={() => setIsHovered(true)} onMouseLeave={() => setIsHovered(false)} style={{
    width: '586px',
    height: 'auto',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    alignItems: 'center',
    paddingTop: '42px',
    paddingBottom: '42px',
    gap: '32px',
    backgroundColor: 'rgba(20, 20, 20, 1)',
    borderRadius: '36px',
    cursor: 'pointer'
  }}>
      <img src={image} alt={title} style={{
      width: '488px',
      height: '293px',
      borderRadius: '32px',
      objectFit: 'cover'
    }} />
      <div style={{
      width: '486px',
      display: 'flex',
      flexDirection: 'row',
      justifyContent: 'space-between',
      alignItems: 'center'
    }}>
        <span style={{
        color: 'white',
        fontSize: '24px',
        fontFamily: '"Barlow", sans-serif',
        fontWeight: 600
      }}>
          {title}
        </span>
        <div style={{
        display: 'flex',
        padding: '14px',
        backgroundColor: isHovered ? 'rgba(89, 176, 255, 1)' : 'rgba(0, 194, 255, 1)',
        borderRadius: '135px',
        transition: 'background-color 0.2s ease'
      }}>
          <img src={icon} alt="Action" style={{
          width: '24px',
          height: '24px'
        }} />
        </div>
      </div>
      <p style={{
      width: '487px',
      color: 'rgba(255, 255, 255, 1)',
      fontSize: '16px',
      fontFamily: '"Barlow", sans-serif',
      fontWeight: 400,
      lineHeight: '24px',
      margin: 0
    }}>
        Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the industry's standard dummy text ever since
      </p>
      <div style={{
      width: '487px',
      display: 'flex',
      justifyContent: 'space-between'
    }}>
        <div style={{
        display: 'flex',
        flexDirection: 'column',
        gap: '10px'
      }}>
          {[1, 2, 3].map(i => <div key={i} style={{
          display: 'flex',
          alignItems: 'center',
          gap: '4px'
        }}>
              <img src="https://storage.googleapis.com/storage.magicpath.ai/user/411851438805884928/figma-assets/b30791ea-e84f-4c33-a0bb-5934eeec5970.svg" alt="bullet" style={{
            width: '15px'
          }} />
              <span style={{
            color: 'white',
            fontSize: '14px',
            fontFamily: '"Barlow", sans-serif'
          }}>Lorem Ipsum is simply dummy text</span>
            </div>)}
        </div>
        <div style={{
        display: 'flex',
        flexDirection: 'column',
        gap: '10px'
      }}>
          {[1, 2].map(i => <div key={i} style={{
          display: 'flex',
          alignItems: 'center',
          gap: '4px'
        }}>
              <img src="https://storage.googleapis.com/storage.magicpath.ai/user/411851438805884928/figma-assets/2294fee1-63be-49d6-9dd8-7eabd2804a2c.svg" alt="bullet" style={{
            width: '15px'
          }} />
              <span style={{
            color: 'white',
            fontSize: '14px',
            fontFamily: '"Barlow", sans-serif'
          }}>Lorem Ipsum is simply dummy text</span>
            </div>)}
        </div>
      </div>
    </article>;
};
